export const theme: Theme = {
    color: '#173C4E',
    link: {
        fg: '#ffffff',
        bg: 'rgb(23, 60, 78)' /*'#b10707'*/,
        padding: '15px 20px',
        border: 'solid'
    },
    text: {
        color: "#24292e",
        bg: "#ffffff",
    },
    banner: {
        fg: '#ffffff',
        bg: '#000000',
        padding: '10px 20px',
    },
    padding: "20px",
};

ReactDOM.render(
    <Provider store={store}>
        <ConnectedRouter history={history}>
        <ThemeProvider theme={theme}>
            <App />
        </ThemeProvider>
        </ConnectedRouter>
    </Provider>,
    document.getElementById('root'));

registerServiceWorker();